<?php
use App\Core\Env;use App\Core\Database;use App\Services\EmailService;use App\Services\SmsService;
$base=dirname(__DIR__);require $base.'/app/core/Env.php';Env::load($base.'/.env');spl_autoload_register(function($c)use($base){$p='App\\';if(str_starts_with($c,$p)){ $relative=substr($c,strlen($p));$parts=explode('\\',$relative);$parts[0]=strtolower($parts[0]);$f=$base.'/app/'.implode('/',$parts).'.php';if(is_file($f))require $f;}});$composer=$base.'/vendor/autoload.php';if(is_file($composer))require $composer;
$pdo=Database::connection();$rules=$pdo->query('SELECT * FROM collection_escalation_rules WHERE active=1 ORDER BY days_overdue')->fetchAll();$invoices=$pdo->query("SELECT i.*,c.display_name,c.email,c.phone,DATEDIFF(CURDATE(),i.due_date) days_overdue FROM invoices i JOIN customers c ON c.id=i.customer_id WHERE i.balance_due>0 AND i.due_date<CURDATE() AND i.status<>'void'")->fetchAll();
foreach($invoices as $inv){foreach($rules as $rule){if((int)$inv['days_overdue']<(int)$rule['days_overdue'])continue;$exists=$pdo->prepare('SELECT 1 FROM collection_escalation_log WHERE invoice_id=? AND rule_id=?');$exists->execute([$inv['id'],$rule['id']]);if($exists->fetchColumn())continue;try{$detail='';if($rule['action_type']==='email'&&$inv['email']){(new EmailService())->sendMail($inv['email'],'Payment reminder for invoice '.$inv['invoice_number'],'<p>Hello '.htmlspecialchars($inv['display_name']).',</p><p>Invoice <strong>'.$inv['invoice_number'].'</strong> has a balance of <strong>$'.number_format((float)$inv['balance_due'],2).'</strong>.</p>');$detail='Email sent';}elseif($rule['action_type']==='sms'&&$inv['phone']){SmsService::send($inv['phone'],'Rock Bluffs Exterior Services: Invoice '.$inv['invoice_number'].' has a balance of $'.number_format((float)$inv['balance_due'],2).'.');$detail='SMS sent';}elseif($rule['action_type']==='hold'){$pdo->prepare("UPDATE customers SET status='inactive' WHERE id=?")->execute([$inv['customer_id']]);$detail='Customer placed on service hold';}else{$detail=$rule['description'];}$pdo->prepare("INSERT INTO collection_escalation_log(invoice_id,rule_id,action_type,status,detail) VALUES(?,?,?,'completed',?)")->execute([$inv['id'],$rule['id'],$rule['action_type'],$detail]);}catch(Throwable $e){$pdo->prepare("INSERT INTO collection_escalation_log(invoice_id,rule_id,action_type,status,detail) VALUES(?,?,?,'failed',?)")->execute([$inv['id'],$rule['id'],$rule['action_type'],$e->getMessage()]);}}}
echo "Collection escalation processing complete.\n";
